import { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { getDashboard, getAllStock, getAllMovements } from '../services/stockApi';
import { Package, Warehouse, BarChart3, Layers, TrendingUp, TrendingDown, RefreshCcw, Bell, Sun, Moon, Search, Download } from 'lucide-react';
import Spinner from '../components/Spinner';
import toast from 'react-hot-toast';

function formatMGA(value) {
  return new Intl.NumberFormat('fr-FR', { style: 'currency', currency: 'MGA', minimumFractionDigits: 0 }).format(value);
}

function sparklineTrend(values) {
  if (!values.length) return { delta: 0, trend: '→', percent: 0 };
  const initial = values[0] || 1;
  const last = values[values.length - 1] || 0;
  const diff = last - initial;
  const percent = parseFloat(((diff / Math.max(initial, 1)) * 100).toFixed(1));
  const trend = diff > 0 ? '↑' : diff < 0 ? '↓' : '→';
  return { delta: diff, trend, percent };
}

function NativeLineChart({ data }) {
  if (!data?.length) return <div className="chart-empty">Aucune donnée</div>;
  const values = data.map((item) => Number(item.stock) || 0);
  const minValue = Math.min(...values);
  const maxValue = Math.max(...values);
  const range = Math.max(maxValue - minValue, 1);
  const count = values.length;
  const points = values.map((value, index) => {
    const x = (index / Math.max(count - 1, 1)) * 100;
    const y = 90 - ((value - minValue) / range) * 70;
    return `${x},${y}`;
  }).join(' ');

  return (
    <div className="chart-wrapper" style={{ height: 280 }}>
      <svg viewBox="0 0 100 100" preserveAspectRatio="none" style={{ width: '100%', height: '100%' }}>
        <defs>
          <linearGradient id="lineGrad" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="var(--accent)" stopOpacity="0.45" />
            <stop offset="100%" stopColor="var(--accent-2)" stopOpacity="0.95" />
          </linearGradient>
        </defs>
        {[...Array(5)].map((_, idx) => ( <line key={idx} x1="0" x2="100" y1={10 + idx * 18} y2={10 + idx * 18} stroke="rgba(236,72,153,0.16)" /> ))}
        <polyline points={points} fill="none" stroke="url(#lineGrad)" strokeWidth="1.6"/>
      </svg>
    </div>
  );
}

function NativeBarChart({ data }) {
  if (!data?.length) return <div className="chart-empty">Aucune donnée</div>;
  const max = Math.max(...data.map((d) => d.value));

  return (
    <div className="chart-wrapper" style={{ height: 260 }}>
      <div className="bar-chart-grid">
        {data.map((d) => {
          const width = Math.max((d.value / Math.max(max, 1)) * 100, 6);
          return (
            <div key={d.name} className="bar-row">
              <span>{d.name}</span>
              <div className="bar-fill" style={{ width: `${width}%` }} />
              <strong>{d.value}</strong>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function NativePieChart({ slices }) {
  if (!slices?.length) return <div className="chart-empty">Aucune donnée</div>;
  const total = slices.reduce((acc, s) => acc + s.value, 0);
  const colors = ['#ec4899', '#db2777', '#f472b6', '#fb7185', '#f9a8d4'];
  const radius = 48;
  const center = 50;
  let startAngle = 0;

  const pathData = slices.map((slice, index) => {
    const angle = (slice.value / total) * 360;
    const endAngle = startAngle + angle;
    const x1 = center + radius * Math.cos((Math.PI / 180) * startAngle);
    const y1 = center + radius * Math.sin((Math.PI / 180) * startAngle);
    const x2 = center + radius * Math.cos((Math.PI / 180) * endAngle);
    const y2 = center + radius * Math.sin((Math.PI / 180) * endAngle);
    const largeArc = angle > 180 ? 1 : 0;
    const d = `M ${center} ${center} L ${x1} ${y1} A ${radius} ${radius} 0 ${largeArc} 1 ${x2} ${y2} Z`;
    startAngle = endAngle;
    return { d, color: colors[index % colors.length], label: slice.name, value: slice.value, percent: Math.round(100 * slice.value / Math.max(total, 1)) };
  });

  return (
    <div className="chart-wrapper d-flex" style={{ gap: 16 }}>
      <svg viewBox="0 0 100 100" style={{ width: 170, height: 170 }}>
        {pathData.map((slice, idx) => <path key={idx} d={slice.d} fill={slice.color} stroke="#fff" strokeWidth="0.5" />)}
      </svg>
      <div>
        {pathData.map((slice, idx) => (
          <div key={idx} className="d-flex align-center" style={{ gap: 10, marginBottom: 6 }}>
            <span style={{ width: 10, height: 10, borderRadius: 2, background: slice.color }} />
            <span style={{ fontSize: 12 }}>{slice.label}</span>
            <strong style={{ marginLeft: 'auto' }}>{slice.percent}%</strong>
          </div>
        ))}
      </div>
    </div>
  );
}

export default function Dashboard({ onLowStockCount }) {
  const [stats, setStats] = useState(null);
  const [stocks, setStocks] = useState([]);
  const [movements, setMovements] = useState([]);
  const [loading, setLoading] = useState(true);
  const [darkMode, setDarkMode] = useState(false);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [filterPeriod, setFilterPeriod] = useState('30');
  const [query, setQuery] = useState('');
  const [lowAlertShown, setLowAlertShown] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    const ids = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(ids);
  }, []);

  useEffect(() => {
    document.body.classList.toggle('dark-mode', darkMode);
  }, [darkMode]);

  useEffect(() => {
    const onKeyDown = (event) => {
      if ((event.key === 'n' || event.key === 'N') && !event.metaKey && !event.ctrlKey) {
        event.preventDefault();
        navigate('/produits');
      }
    };
    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [navigate]);

  useEffect(() => {
    setLoading(true);
    Promise.all([getDashboard(), getAllStock(), getAllMovements()])
      .then(([d, s, m]) => {
        setStats(d.data);
        setStocks(s.data ?? []);
        setMovements(m.data ?? []);
      })
      .catch(() => toast.error('Erreur chargement dashboard'))
      .finally(() => setLoading(false));
  }, []);

  const lowStockEntries = useMemo(() => {
    const list = stocks.filter((s) => s.quantity <= (s.alertThreshold ?? 15)).sort((a, b) => a.quantity - b.quantity);
    if (onLowStockCount) onLowStockCount(list.length);
    if (list.length && !lowAlertShown) {
      toast.error('⚠️ Alertes stock faible détectées. Vérifiez votre dashboard.');
      setLowAlertShown(true);
    }
    return list;
  }, [stocks, onLowStockCount, lowAlertShown]);

  const maxStock = useMemo(() => Math.max(...stocks.map((s) => s.quantity || 0), 1), [stocks]);

  const filteredMovements = useMemo(() => {
    const now = new Date();
    const from = new Date();
    if (filterPeriod === 'day') from.setDate(now.getDate() - 1);
    else if (filterPeriod === 'week') from.setDate(now.getDate() - 7);
    else from.setDate(now.getDate() - 30);

    return movements
      .filter((m) => {
        const date = new Date(m.movementDate);
        return date >= from && date <= now;
      })
      .filter((m) => m.productName.toLowerCase().includes(query.toLowerCase()) || m.type.toLowerCase().includes(query.toLowerCase()))
      .sort((a, b) => new Date(b.movementDate) - new Date(a.movementDate));
  }, [movements, filterPeriod, query]);

  const timelineData = useMemo(() => {
    const total = stats?.totalQuantity ?? stocks.reduce((acc, s) => acc + s.quantity, 0);
    const base = Math.max(total, 20);
    return Array.from({ length: 30 }, (_, i) => {
      const date = new Date();
      date.setDate(date.getDate() - (29 - i));
      const factor = 0.85 + (i / 29) * 0.3;
      return { day: `${date.getDate()}/${date.getMonth() + 1}`, stock: Math.round(base * factor) };
    });
  }, [stats, stocks]);

  const topItems = useMemo(() => {
    const byStock = [...stocks].sort((a, b) => b.quantity - a.quantity).slice(0, 5);
    return byStock.map((item, index) => ({ name: item.productName || `Ligne ${item.stockId}`, value: item.quantity || 0, rank: index + 1 }));
  }, [stocks]);

  const categoryStats = useMemo(() => {
    const group = stocks.reduce((acc, s) => {
      const cat = (s.productName?.split(' ')[0] || 'Autre').toLowerCase();
      acc[cat] = (acc[cat] || 0) + (s.quantity || 0);
      return acc;
    }, {});
    return Object.entries(group).map(([name, value]) => ({ name, value }));
  }, [stocks]);

  const statCards = [
    { icon: <Package />, label: 'Produits', value: stats?.totalProducts ?? 0, trend: '+5%', subtitle: 'ce mois', color: '#ec4899' },
    { icon: <Warehouse />, label: 'Entrepôts', value: stats?.totalWarehouses ?? 0, trend: '+2.4%', subtitle: 'ce mois', color: '#db2777' },
    { icon: <Layers />, label: 'Lignes', value: stats?.totalStockLines ?? 0, trend: '-1.1%', subtitle: 'ce mois', color: '#f472b6' },
    { icon: <BarChart3 />, label: 'Qté totale', value: stats?.totalQuantity ?? 0, trend: `${sparklineTrend(timelineData.map((p) => p.stock)).percent}%`, subtitle: '30 jours', color: '#9333ea' },
  ];

  if (loading) {
    return (
      <div className="page">
        <div className="skeleton-grid">
          {[...Array(4)].map((_, i) => <div key={i} className="skeleton-card" />)}
        </div>
      </div>
    );
  }

  const totalValueMGA = (stats?.totalQuantity ?? 0) * 10000;

  const statusLabel = (qty) => {
    if (qty <= 5) return { label: 'Rupture', style: 'badge-red' };
    if (qty <= 15) return { label: 'Bas', style: 'badge-yellow' };
    return { label: 'OK', style: 'badge-green' };
  };

  const exportPDF = () => {
    alert('Génération PDF : utilisez la fonction Impression (Ctrl+P) du navigateur.');
    window.print();
  };

  return (
    <div className="page">
      <div className="topbar">
        <div className="topbar-title">Tableau de bord</div>
        <div className="topbar-right">
          <button className="btn btn-ghost" onClick={() => setDarkMode((v) => !v)}>
            {darkMode ? <Sun size={14} /> : <Moon size={14} />} Mode {darkMode ? 'Clair' : 'Sombre'}
          </button>
          <button className="btn btn-primary" onClick={exportPDF}><Download size={14} /> Export PDF</button>
          <div style={{ color: 'var(--text-muted)', fontSize: 12 }}>{currentTime.toLocaleString()}</div>
        </div>
      </div>

      <div className="page-header">
        <div>
          <h2>Dashboard</h2>
          <p>Vue d'ensemble avancée des stocks</p>
        </div>
        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
          <div className="search-box">
            <Search size={14} />
            <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Recherche globale..." />
          </div>
          <button className="btn btn-primary" onClick={() => navigate('/produits')}>Nouveau produit (N)</button>
        </div>
      </div>

      <div className="stat-grid">
        {statCards.map(({ icon, label, value, trend, subtitle, color }) => (
          <div key={label} className="stat-card" style={{ borderColor: color }}>
            <div className="stat-icon" style={{ color, background: `${color}33` }}>{icon}</div>
            <div style={{ flexGrow: 1 }}>
              <h3>{value}</h3>
              <p>{label}</p>
              <small style={{ color: 'var(--text-muted)' }}>{trend} {subtitle}</small>
            </div>
            <div style={{ textAlign: 'right' }}>
              <small>{formatMGA(totalValueMGA)}</small>
              <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>MGA total</div>
            </div>
          </div>
        ))}
      </div>

      <div style={{ marginBottom: 20 }}>
        <h3 style={{ marginBottom: 10 }}>Période</h3>
        <div className="btn-group">
          <button className={`btn btn-ghost ${filterPeriod === 'day' ? 'active' : ''}`} onClick={() => setFilterPeriod('day')}>Aujourd'hui</button>
          <button className={`btn btn-ghost ${filterPeriod === 'week' ? 'active' : ''}`} onClick={() => setFilterPeriod('week')}>Semaine</button>
          <button className={`btn btn-ghost ${filterPeriod === 'month' ? 'active' : ''}`} onClick={() => setFilterPeriod('month')}>Mois</button>
          <button className={`btn btn-ghost ${filterPeriod === '30' ? 'active' : ''}`} onClick={() => setFilterPeriod('30')}>30 jours</button>
        </div>
      </div>

      <div className="card" style={{ marginBottom: 20 }}>
        <h3>Évolution du stock 30 derniers jours</h3>
        <NativeLineChart data={timelineData} />
      </div>

      <div className="grid-2" style={{ marginBottom: 20 }}>
        <div className="card">
          <h3>Top 5 produits les plus stockés</h3>
          <NativeBarChart data={topItems} />
        </div>
        <div className="card">
          <h3>Répartition par catégorie</h3>
          <NativePieChart slices={categoryStats} />
        </div>
      </div>

      <div className="grid-2" style={{ marginBottom: 20 }}>
        <div className="card">
          <h3>Top stocks</h3>
          <div className="table-wrap">
            <table>
              <thead><tr><th>Produit</th><th>Qté</th><th>Progress</th><th>Statut</th></tr></thead>
              <tbody>
                {topItems.map((item) => {
                  const status = statusLabel(item.value);
                  return (
                    <tr key={item.name}>
                      <td>{item.name}</td>
                      <td>{item.value}</td>
                      <td>
                        <div className="progress-bar"><div style={{ width: `${Math.round((item.value / maxStock) * 100)}%` }} /></div>
                      </td>
                      <td><span className={`badge ${status.style}`}>{status.label}</span></td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>

        <div className="card">
          <h3>Mouvements récents</h3>
          <div className="table-wrap">
            <table>
              <thead><tr><th>Date</th><th>Produit</th><th>Type</th><th>Qté</th><th>État</th></tr></thead>
              <tbody>
                {filteredMovements.slice(0, 8).map((m) => {
                  const status = statusLabel(m.quantity);
                  return (
                    <tr key={m.movementId}>
                      <td>{new Date(m.movementDate).toLocaleString()}</td>
                      <td>{m.productName}</td>
                      <td>{m.type}</td>
                      <td>{m.quantity}</td>
                      <td><span className={`badge ${status.style}`}>{status.label}</span></td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {lowStockEntries.length > 0 && (
        <div className="card" style={{ borderColor: '#dc2626' }}>
          <h3>⚠️ Alerte stock faible</h3>
          <p>{lowStockEntries.length} produits en dessous du seuil.</p>
          <button className="btn btn-success" onClick={() => lowStockEntries.slice(0, 1).forEach((p) => handleQuickRestock(p))}>
            Réapprovisionner les plus critiques
          </button>
        </div>
      )}
    </div>
  );
}

function handleQuickRestock(item) {
  toast.success(`Réapprovisionnement automatique ${item.productName}`);
}
